class Solution(object):
    def queryString(self, s, n):
        needed = set(bin(i)[2:] for i in range(1, n + 1))
        for i in range(len(s) - max(len(bin(j)[2:]) for j in range(1, n + 1)) + 1):
            for length in range(1, 31):
                if i + length > len(s):
                    break
                substr = s[i:i+length]
                needed.discard(substr)
        return len(needed) == 0
